BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?body WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("the APS and Its Role in TMT")))
  OPTIONAL { ?elem vocab:comment|vocab:body ?body }
  OPTIONAL {
    ?elem vocab:ownedComment+ ?c .
    OPTIONAL { ?c vocab:body ?body }
  }
  OPTIONAL {
    ?elem rdf:type ?type .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?commentText WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS%20Mission")))
  OPTIONAL {
    ?elem vocab:ownedComment+ ?c .
    ?c vocab:body ?commentText .
  }
  OPTIONAL {
    ?elem vocab:comment ?commentText .
  }
}
LIMIT 25
